import {Edge} from 'butterfly-dag';
import $ from 'jquery';

class BaseEdge extends Edge {
  draw(obj) {
    let path = super.draw(obj);
    $(path).addClass('base-link');
    return path;
  }
  // 随时定制label的位置和样式
  redrawLabel() {
    if (this._labelDom0) {
      let beginPoint = this.dom.getPointAtLength(0);
      $(this._labelDom0)
        .css('left', beginPoint.x - this._labelDom0.offsetWidth / 2 + 20)
        .css('top', beginPoint.y - this._labelDom0.offsetHeight / 2 + 20);
    }
    if (this._labelDom1) {
      let pathLength = this.dom.getTotalLength();
      let endPoint = this.dom.getPointAtLength(pathLength);
      $(this._labelDom1)
        .css('left', endPoint.x - this._labelDom1.offsetWidth / 2 - 20)
        .css('top', endPoint.y - this._labelDom1.offsetHeight / 2 + 20);
    }
  }
  drawLabel(texts) {
    let dom = null;
    if (texts) {
      dom = document.createDocumentFragment();
      let inText = texts[0];
      let outText = texts[1];
      if (inText) {
        let dom0 = $(`<span class="in-label label">${inText}</span>`)[0];
        dom.append(dom0);
        this._labelDom0 = dom0;
      }
      if (outText) {
        let dom1 = $(`<span class="out-label label">${outText}</span>`)[0];
        dom.append(dom1);
        this._labelDom1 = dom1;
      }
    }
    return dom;
  }
}

export default BaseEdge;

import {Endpoint, Tips} from 'butterfly-dag';
import $ from 'jquery';

class BaseEndpoint extends Endpoint {
  mounted() {
    Tips.createTip({
      targetDom: this.dom,
      genTipDom: (data) => {
        return $('<div>this is a tips</div>')[0];
      },
      placement: 'top'
    });
  }
  draw(obj) {
    let point = super.draw(obj);
    $(point).addClass('purple-point');
    return point;
  }
}

export default BaseEndpoint;

import {Group} from 'butterfly-dag';
import $ from 'jquery';
import _ from 'lodash';

class BaseGroup extends Group {
  draw(obj) {
    let _dom = obj.dom;
    if (!_dom) {
      _dom = $('<div></div>')
        .attr('class', 'group')
        .css('top', obj.top)
        .css('left', obj.left)
        .attr('id', obj.id);
    }
    let group = $(_dom);

    this._container = $('<div></div>')
      .attr('class', 'container');

    group.append(this._container);

    // 添加文字
    if (_.get(obj, 'options.text')) {
      group.append(`<span class="text">${obj.options.text}</span>`);
    }

    return _dom;
  }
}

export default BaseGroup;

import React, {Component} from 'react';
import ReactDOM from 'react-dom';
import {Canvas} from 'butterfly-dag';
import mockData from './data';
import './index.less';
import 'butterfly-dag/dist/index.css';

class System extends Component {
  constructor() {
    super();
  }
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          shapeType: 'Straight'
        }
      }
    });
    this.canvas.draw(mockData);
  }
  render() {
    return (
      <div className='system-page'>
        <div className="system-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

ReactDOM.render(<System />, document.getElementById('root'));

