      text-align: center;
      background: @butterfly-theme-color;
      vertical-align: middle;
      border-radius: 5px;
    }
    .base-link {
      stroke: #4b4f6b;
      stroke-width: 1px;
    }
    .group {
      > .text {
        position: absolute;
        top: 20px;
        left: 108px;
        width: 100px;
      }
    }
    .label {
      position: absolute;
      color: @butterfly-normal-font-color;
      font-size: 12px;
    }
    .label:hover {
